import { selectBackgroundShader } from "../shader-catalog.js";
import { selectPostProcessingPasses } from "../postprocessing-catalog.js";
import { selectParticleSystem, getParticleEntry } from "../particle-catalog.js";
/**
 * WebGL / React Three Fiber Component Generator
 *
 * All 4 materials are fully implemented. Geometry is driven by ch15_biomarker:
 *   organic   → torusKnotGeometry (flowing, irregular)
 *   fractal   → icosahedronGeometry (geodesic, self-similar)
 *   monolithic → boxGeometry / octahedronGeometry (rigid, architectural)
 *
 * Roughness, transmission, and intensity values come directly from the genome
 * — no hardcoded aesthetic decisions.
 */
export class WebGLGenerator {
    generateR3F(genome) {
        const { material, roughness, transmission } = genome.chromosomes.ch14_physics;
        const { geometry, complexity } = genome.chromosomes.ch15_biomarker;
        const { intensity } = genome.chromosomes.ch13_atmosphere;
        const { animate } = genome.chromosomes.ch18_rendering;
        const { hue, saturation, lightness } = genome.chromosomes.ch5_color_primary;
        const entropy = genome.chromosomes.ch12_signature?.entropy ?? 0.5;
        // Derive geometry args from biomarker + entropy
        const geometryJSX = this.buildGeometry(geometry, complexity, entropy);
        const colorVal = `hsl(${hue}, ${Math.round(saturation * 100)}%, ${Math.round(lightness * 100)}%)`;
        const animateCode = animate
            ? `useFrame((_, delta) => { if (meshRef.current) { meshRef.current.rotation.x += delta * ${(0.05 + complexity * 0.2).toFixed(3)}; meshRef.current.rotation.y += delta * ${(0.08 + complexity * 0.3).toFixed(3)}; } });`
            : "// Animation disabled by genome (ch18_rendering.animate = false)";
        const materialJSX = this.buildMaterial(material, roughness, transmission, intensity, colorVal);
        return `// React Three Fiber — Generated by Genome MCP
// Material: ${material} | Geometry: ${geometry} | DNA: ${genome.dnaHash.slice(0, 8)}
import { useRef } from 'react';
import { Canvas, useFrame } from '@react-three/fiber';
import { Environment${material === "glass" ? ", MeshTransmissionMaterial" : ""} } from '@react-three/drei';
import type { Mesh } from 'three';

function ProceduralOrganism() {
  const meshRef = useRef<Mesh>(null);

  ${animateCode}

  return (
    <>
      {/* Background glow */}
      <mesh scale={2} position={[0, 0, -2]}>
        <sphereGeometry args={[1.5, 32, 32]} />
        <meshBasicMaterial color="${colorVal}" transparent opacity={${(0.05 + intensity * 0.1).toFixed(2)}} />
      </mesh>

      {/* Main organism */}
      <mesh ref={meshRef} scale={1.2}>
        ${geometryJSX}
        ${materialJSX}
      </mesh>
    </>
  );
}

export function Procedural3D() {
  return (
    <Canvas camera={{ position: [0, 0, 6], fov: 50 }}>
      <ambientLight intensity={${(0.3 + intensity * 0.5).toFixed(2)}} />
      <pointLight position={[5, 5, 5]} intensity={${(1.0 + intensity).toFixed(2)}} color="${colorVal}" />
      <Environment preset="${this.selectEnvironment(material)}" />
      <ProceduralOrganism />
    </Canvas>
  );
}`;
    }
    buildGeometry(geometry, complexity, entropy = 0.5) {
        // Map expanded geometry types to base categories
        const geometryMap = {
            organic: "organic", cellular: "organic", fibrous: "organic", shell: "organic", spiral: "organic",
            fractal: "fractal", crystalline: "fractal", lattice: "fractal", voronoi: "fractal", diffusion: "fractal",
            monolithic: "monolithic", granular: "monolithic", radial: "monolithic", linear: "monolithic",
            erosion: "monolithic", growth: "monolithic"
        };
        const baseGeometry = geometryMap[geometry] || "organic";
        if (baseGeometry === "organic") {
            // Select shape based on entropy × complexity so same keyword → different geometry per DNA
            // 6 distinct organic shapes — torusKnot is just one of them
            const shapeSelector = (entropy * 0.6 + complexity * 0.4);
            if (shapeSelector < 0.15) {
                // Simple torus — minimal, ring-like (low entropy, low complexity)
                const r = (0.3 + complexity * 0.4).toFixed(2);
                const tube = (0.08 + complexity * 0.12).toFixed(2);
                return `<torusGeometry args={[${r}, ${tube}, 64, 120]} />`;
            }
            else if (shapeSelector < 0.30) {
                // Sphere with high segment count — cellular, membrane-like
                const segments = Math.round(32 + complexity * 64);
                return `<sphereGeometry args={[1.1, ${segments}, ${segments}} />`;
            }
            else if (shapeSelector < 0.50) {
                // Classic torusKnot with varied p/q from complexity
                const p = Math.max(2, Math.round(2 + complexity * 5));
                const q = Math.max(3, Math.round(3 + complexity * 4));
                return `<torusKnotGeometry args={[1, ${(0.25 + complexity * 0.2).toFixed(2)}, 128, 32, ${p}, ${q}]} />`;
            }
            else if (shapeSelector < 0.65) {
                // Extreme torusKnot — high p/q for chaotic biology (high entropy)
                const p = Math.max(3, Math.round(3 + entropy * 9));
                const q = Math.max(5, Math.round(5 + entropy * 7));
                return `<torusKnotGeometry args={[0.9, ${(0.15 + entropy * 0.15).toFixed(2)}, 256, 32, ${p}, ${q}]} />`;
            }
            else if (shapeSelector < 0.80) {
                // Icosahedron (geodesic sphere) — biological cell wall
                const detail = Math.min(5, Math.round(entropy * 5));
                return `<icosahedronGeometry args={[1.15, ${detail}]} />`;
            }
            else {
                // Dodecahedron — 12-face platonic solid, pentagonal biology
                return `<dodecahedronGeometry args={[1.1, ${Math.round(entropy * 2)}]} />`;
            }
        }
        else if (baseGeometry === "fractal") {
            // Icosahedron — geodesic, self-similar. Detail level from complexity.
            const detail = Math.min(4, Math.floor(complexity * 5));
            return `<icosahedronGeometry args={[1.2, ${detail}]} />`;
        }
        else {
            // Monolithic / default — octahedron for medium complexity, box for low
            if (complexity > 0.5) {
                return `<octahedronGeometry args={[1.2, ${Math.floor(complexity * 3)}]} />`;
            }
            return `<boxGeometry args={[${(1.5 + complexity).toFixed(1)}, ${(1.5 + complexity).toFixed(1)}, ${(1.5 + complexity).toFixed(1)}]} />`;
        }
    }
    buildMaterial(material, roughness, transmission, intensity, color) {
        // Map expanded material types to base categories
        const materialMap = {
            glass: "glass", holographic: "glass", iridescent: "glass",
            metallic: "metallic", chrome: "metallic", brushed: "metallic", pearlescent: "metallic",
            neumorphism: "neumorphism", satin: "neumorphism", gloss: "neumorphism", rubber: "neumorphism",
            matte: "matte", velvet: "matte", ceramic: "matte", wood: "matte", stone: "matte"
        };
        const baseMaterial = materialMap[material] || "matte";
        if (baseMaterial === "glass") {
            return `<MeshTransmissionMaterial
          roughness={${roughness.toFixed(3)}}
          transmission={${Math.max(0.7, transmission).toFixed(3)}}
          thickness={${(0.5 + intensity).toFixed(2)}}
          ior={${(1.4 + intensity * 0.4).toFixed(2)}}
          color="${color}"
          emissive="${color}"
          emissiveIntensity={${(intensity * 0.3).toFixed(2)}}
        />`;
        }
        else if (baseMaterial === "metallic") {
            return `<meshStandardMaterial
          metalness={1}
          roughness={${roughness.toFixed(3)}}
          color="${color}"
          envMapIntensity={${(0.5 + intensity * 1.5).toFixed(2)}}
        />`;
        }
        else if (baseMaterial === "neumorphism") {
            // Soft, light-extruded — phong with specular glow
            return `<meshPhongMaterial
          color="${color}"
          specular="${color}"
          shininess={${Math.round(30 + intensity * 70)}}
          emissive="${color}"
          emissiveIntensity={${(intensity * 0.15).toFixed(2)}}
        />`;
        }
        else {
            // Matte / default — no reflections, flat lambert
            return `<meshLambertMaterial
          color="${color}"
          emissive="${color}"
          emissiveIntensity={${(intensity * 0.05).toFixed(2)}}
        />`;
        }
    }
    selectEnvironment(material) {
        const envMap = {
            glass: "city", holographic: "city", iridescent: "studio",
            metallic: "studio", chrome: "studio", brushed: "warehouse",
            neumorphism: "sunset", satin: "sunset", gloss: "sunset",
            matte: "apartment", velvet: "apartment", ceramic: "apartment",
            wood: "forest", stone: "dawn"
        };
        return envMap[material] || "apartment";
    }
    // ── Scene type dispatcher ─────────────────────────────────────────────────
    /**
     * Generate a WebGL scene based on ch15_biomarker.sceneType.
     * Falls back to decorative_mesh (existing behaviour) when unset.
     */
    generateScene(genome) {
        const ch15 = genome.chromosomes.ch15_biomarker;
        const sceneType = ch15?.sceneType ?? "decorative_mesh";
        switch (sceneType) {
            case "decorative_mesh": return this.generateR3F(genome);
            case "particle_field": return this.generateParticleField(genome);
            case "background_shader": return this.generateBackgroundShader(genome);
            case "image_reveal": return this.generateImageReveal(genome);
            case "product_viewer": return this.generateProductViewer(genome);
            case "scroll_journey": return this.generateScrollJourney(genome);
            case "transition_canvas": return this.generateTransitionCanvas(genome);
            default: return this.generateR3F(genome);
        }
    }
    // ── particle_field ────────────────────────────────────────────────────────
    generateParticleField(genome) {
        const ch15 = genome.chromosomes.ch15_biomarker;
        const ch12 = genome.chromosomes.ch12_signature;
        const ch8 = genome.chromosomes.ch8_motion;
        const ch5 = genome.chromosomes.ch5_color_primary;
        const ch13 = genome.chromosomes.ch13_atmosphere;
        const philosophy = ch12?.designPhilosophy ?? "editorial";
        const physics = ch8?.physics ?? "none";
        const fx = ch13?.fx ?? "";
        const entropy = ch12?.entropy ?? 0.5;
        const complexity = ch15?.complexity ?? 0.5;
        const hue = Math.round(ch5?.hue ?? 210);
        const sat = Math.round((ch5?.saturation ?? 0.6) * 100);
        const lit = Math.round((ch5?.lightness ?? 0.5) * 100);
        const particleType = selectParticleSystem({
            philosophy, physics, fx, sector: "", entropy, complexity, hasWebGL: true,
        });
        const entry = getParticleEntry(particleType);
        const count = Math.round(entry.countRange[0] + (entry.countRange[1] - entry.countRange[0]) * complexity);
        const color = `hsl(${hue}, ${sat}%, ${lit}%)`;
        return `// Three.js Particle Field — Generated by Genome MCP
// System: ${particleType} | Count: ${count} | DNA: ${genome.dnaHash.slice(0, 8)}
import { useRef, useMemo } from 'react';
import { Canvas, useFrame } from '@react-three/fiber';
import * as THREE from 'three';

function ParticleSystem() {
  const mesh = useRef<THREE.Points>(null);
  const { positions, velocities } = useMemo(() => {
    const positions = new Float32Array(${count} * 3);
    const velocities = new Float32Array(${count} * 3);
    for (let i = 0; i < ${count}; i++) {
      positions[i*3]   = (Math.random() - 0.5) * 10;
      positions[i*3+1] = (Math.random() - 0.5) * 10;
      positions[i*3+2] = (Math.random() - 0.5) * 10;
      velocities[i*3]   = (Math.random() - 0.5) * 0.01;
      velocities[i*3+1] = (Math.random() - 0.5) * 0.01;
      velocities[i*3+2] = (Math.random() - 0.5) * 0.005;
    }
    return { positions, velocities };
  }, []);

  useFrame(() => {
    if (!mesh.current) return;
    const pos = mesh.current.geometry.attributes.position.array as Float32Array;
    for (let i = 0; i < ${count}; i++) {
      pos[i*3]   += velocities[i*3];
      pos[i*3+1] += velocities[i*3+1];
      pos[i*3+2] += velocities[i*3+2];
      if (Math.abs(pos[i*3]) > 5)   velocities[i*3]   *= -1;
      if (Math.abs(pos[i*3+1]) > 5) velocities[i*3+1] *= -1;
      if (Math.abs(pos[i*3+2]) > 5) velocities[i*3+2] *= -1;
    }
    mesh.current.geometry.attributes.position.needsUpdate = true;
  });

  return (
    <points ref={mesh}>
      <bufferGeometry>
        <bufferAttribute attach="attributes-position" args={[positions, 3]} />
      </bufferGeometry>
      <pointsMaterial size={0.04} color="${color}" transparent opacity={0.7} sizeAttenuation />
    </points>
  );
}

export function ParticleCanvas() {
  return (
    <Canvas style={{ position: 'absolute', inset: 0 }} camera={{ position: [0, 0, 8], fov: 60 }}>
      <ambientLight intensity={0.5} />
      <ParticleSystem />
    </Canvas>
  );
}`;
    }
    // ── background_shader ─────────────────────────────────────────────────────
    generateBackgroundShader(genome) {
        const ch12 = genome.chromosomes.ch12_signature;
        const ch8 = genome.chromosomes.ch8_motion;
        const ch5 = genome.chromosomes.ch5_color_primary;
        const ch13 = genome.chromosomes.ch13_atmosphere;
        const ch14 = genome.chromosomes.ch14_physics;
        const ch6 = genome.chromosomes.ch6_color_temp;
        const philosophy = ch12?.designPhilosophy ?? "editorial";
        const physics = ch8?.physics ?? "none";
        const fx = ch13?.fx ?? "";
        const material = ch14?.material ?? "standard";
        const entropy = ch12?.entropy ?? 0.5;
        const hue = ch5?.hue ?? 210;
        const sector = "";
        const shaderType = selectBackgroundShader({ philosophy, physics, fx, material, sector, entropy, hue });
        const colorVal = `vec3(${(ch5?.hue ?? 210) / 360}.0, ${(ch5?.saturation ?? 0.6).toFixed(2)}, ${(ch5?.lightness ?? 0.5).toFixed(2)})`;
        const glsl = shaderType
            ? this.getShaderGLSL(shaderType, colorVal)
            : `// No background shader selected for this genome`;
        return `// Three.js Background Shader — Generated by Genome MCP
// Shader: ${shaderType ?? "none"} | DNA: ${genome.dnaHash.slice(0, 8)}
import { useRef } from 'react';
import { Canvas, useFrame } from '@react-three/fiber';
import * as THREE from 'three';

const vertexShader = \`
  varying vec2 vUv;
  void main() { vUv = uv; gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0); }
\`;

const fragmentShader = \`
${glsl}
\`;

function ShaderPlane() {
  const ref = useRef<THREE.Mesh>(null);
  const uniforms = useRef({ uTime: { value: 0 }, uVelocity: { value: 0 } });
  useFrame(({ clock }) => {
    if (ref.current) {
      (ref.current.material as THREE.ShaderMaterial).uniforms.uTime.value = clock.getElapsedTime();
    }
  });
  return (
    <mesh ref={ref} scale={[2, 2, 1]}>
      <planeGeometry args={[2, 2]} />
      <shaderMaterial vertexShader={vertexShader} fragmentShader={fragmentShader} uniforms={uniforms.current} />
    </mesh>
  );
}

export function BackgroundCanvas() {
  return (
    <Canvas orthographic camera={{ near: -1, far: 1, zoom: 1 }} style={{ position: 'absolute', inset: 0, zIndex: 0 }}>
      <ShaderPlane />
    </Canvas>
  );
}`;
    }
    // ── image_reveal ──────────────────────────────────────────────────────────
    generateImageReveal(genome) {
        const ch12 = genome.chromosomes.ch12_signature;
        const entropy = ch12?.entropy ?? 0.5;
        return `// Three.js Image Reveal — Generated by Genome MCP
// Technique: dissolve_noise | Entropy: ${entropy.toFixed(2)} | DNA: ${genome.dnaHash.slice(0, 8)}
import { useRef, useEffect } from 'react';
import { Canvas, useFrame, useLoader } from '@react-three/fiber';
import * as THREE from 'three';
import { TextureLoader } from 'three';

const vertexShader = \`
  varying vec2 vUv;
  void main() { vUv = uv; gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0); }
\`;
const fragmentShader = \`
  uniform sampler2D uTexture;
  uniform float uProgress;
  varying vec2 vUv;
  float rand(vec2 n) { return fract(sin(dot(n, vec2(12.9898, 4.1414))) * 43758.5453); }
  float noise(vec2 p) { vec2 i = floor(p); vec2 f = fract(p); float a = rand(i); float b = rand(i + vec2(1.0, 0.0)); float c = rand(i + vec2(0.0, 1.0)); float d = rand(i + vec2(1.0, 1.0)); return mix(mix(a,b,f.x), mix(c,d,f.x), f.y); }
  void main() {
    float n = noise(vUv * 6.0);
    float mask = step(n, uProgress);
    vec4 tex = texture2D(uTexture, vUv);
    gl_FragColor = vec4(tex.rgb, tex.a * mask);
  }
\`;

function ImagePlane({ src }: { src: string }) {
  const ref = useRef<THREE.Mesh>(null);
  const texture = useLoader(TextureLoader, src);
  const uniforms = useRef({ uTexture: { value: texture }, uProgress: { value: 0 } });
  useEffect(() => {
    let p = 0;
    const id = setInterval(() => {
      p = Math.min(1, p + 0.02);
      if (ref.current) (ref.current.material as THREE.ShaderMaterial).uniforms.uProgress.value = p;
      if (p >= 1) clearInterval(id);
    }, 16);
  }, []);
  return (
    <mesh ref={ref}>
      <planeGeometry args={[2, 1.5]} />
      <shaderMaterial vertexShader={vertexShader} fragmentShader={fragmentShader} uniforms={uniforms.current} transparent />
    </mesh>
  );
}

export function ImageRevealCanvas({ src }: { src: string }) {
  return (
    <Canvas camera={{ position: [0, 0, 2], fov: 50 }}>
      <ImagePlane src={src} />
    </Canvas>
  );
}`;
    }
    // ── product_viewer ────────────────────────────────────────────────────────
    generateProductViewer(genome) {
        const ch14 = genome.chromosomes.ch14_physics;
        const ch13 = genome.chromosomes.ch13_atmosphere;
        const intensity = ch13?.intensity ?? 0.5;
        return `// Three.js Product Viewer — Generated by Genome MCP
// DNA: ${genome.dnaHash.slice(0, 8)}
import { Suspense } from 'react';
import { Canvas } from '@react-three/fiber';
import { OrbitControls, Environment, useGLTF } from '@react-three/drei';

function ProductModel({ url }: { url: string }) {
  const { scene } = useGLTF(url);
  return <primitive object={scene} scale={1.5} />;
}

export function ProductViewer({ modelUrl }: { modelUrl: string }) {
  return (
    <Canvas camera={{ position: [0, 0, 5], fov: 45 }}>
      <ambientLight intensity={${(0.3 + intensity * 0.4).toFixed(2)}} />
      <directionalLight position={[5, 5, 5]} intensity={${(0.8 + intensity * 0.5).toFixed(2)}} />
      <Suspense fallback={null}>
        <ProductModel url={modelUrl} />
        <Environment preset="${this.selectEnvironment(ch14?.material ?? "matte")}" />
      </Suspense>
      <OrbitControls enableZoom={true} enablePan={false} autoRotate autoRotateSpeed={1.5} />
    </Canvas>
  );
}`;
    }
    // ── scroll_journey ────────────────────────────────────────────────────────
    generateScrollJourney(genome) {
        const ch5 = genome.chromosomes.ch5_color_primary;
        const hue = Math.round(ch5?.hue ?? 210);
        const sat = Math.round((ch5?.saturation ?? 0.6) * 100);
        const lit = Math.round((ch5?.lightness ?? 0.5) * 100);
        return `// Three.js Scroll Journey — Generated by Genome MCP
// Camera follows CatmullRomCurve3 driven by scroll position
// DNA: ${genome.dnaHash.slice(0, 8)}
import { useRef, useEffect } from 'react';
import { Canvas, useFrame, useThree } from '@react-three/fiber';
import * as THREE from 'three';

const CURVE_POINTS = [
  new THREE.Vector3(-3, 0, 0),
  new THREE.Vector3(-1, 2, -3),
  new THREE.Vector3(1, -1, -6),
  new THREE.Vector3(3, 1, -9),
  new THREE.Vector3(0, 0, -12),
];
const curve = new THREE.CatmullRomCurve3(CURVE_POINTS);

function ScrollCamera() {
  const { camera } = useThree();
  const progress = useRef(0);
  useEffect(() => {
    const onScroll = () => {
      const max = document.body.scrollHeight - window.innerHeight;
      progress.current = window.scrollY / max;
    };
    window.addEventListener('scroll', onScroll, { passive: true });
    return () => window.removeEventListener('scroll', onScroll);
  }, []);
  useFrame(() => {
    const p = progress.current;
    const pos = curve.getPoint(p);
    const look = curve.getPoint(Math.min(1, p + 0.05));
    camera.position.copy(pos);
    camera.lookAt(look);
  });
  return null;
}

export function ScrollJourneyCanvas() {
  return (
    <Canvas style={{ position: 'fixed', inset: 0, zIndex: -1 }} camera={{ fov: 60 }}>
      <ambientLight intensity={0.4} />
      <pointLight position={[0, 5, -5]} intensity={1.5} color="hsl(${hue}, ${sat}%, ${lit}%)" />
      <ScrollCamera />
      {CURVE_POINTS.map((pt, i) => (
        <mesh key={i} position={pt}>
          <sphereGeometry args={[0.15, 16, 16]} />
          <meshStandardMaterial color="hsl(${hue}, ${sat}%, ${lit}%)" emissive="hsl(${hue}, ${sat}%, ${lit}%)" emissiveIntensity={0.5} />
        </mesh>
      ))}
    </Canvas>
  );
}`;
    }
    // ── transition_canvas ─────────────────────────────────────────────────────
    generateTransitionCanvas(genome) {
        const ch5 = genome.chromosomes.ch5_color_primary;
        const colorVal = `hsl(${Math.round(ch5?.hue ?? 210)}, ${Math.round((ch5?.saturation ?? 0.6) * 100)}%, ${Math.round((ch5?.lightness ?? 0.5) * 100)}%)`;
        return `// Three.js Transition Canvas — Generated by Genome MCP
// Persistent canvas for page-to-page shader dissolve
// DNA: ${genome.dnaHash.slice(0, 8)}
import { useRef } from 'react';
import { Canvas, useFrame } from '@react-three/fiber';
import * as THREE from 'three';

const fragmentShader = \`
  uniform float uProgress;
  uniform vec3 uColor;
  varying vec2 vUv;
  float rand(vec2 n) { return fract(sin(dot(n, vec2(12.9898, 4.1414))) * 43758.5453); }
  void main() {
    float n = rand(vUv * 8.0 + uProgress);
    float mask = step(n, uProgress);
    gl_FragColor = vec4(uColor, mask);
  }
\`;
const vertexShader = \`
  varying vec2 vUv;
  void main() { vUv = uv; gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0); }
\`;

function TransitionPlane({ progress }: { progress: number }) {
  const ref = useRef<THREE.Mesh>(null);
  useFrame(() => {
    if (ref.current) {
      (ref.current.material as THREE.ShaderMaterial).uniforms.uProgress.value = progress;
    }
  });
  const color = new THREE.Color("${colorVal}");
  return (
    <mesh ref={ref} scale={[2, 2, 1]}>
      <planeGeometry args={[2, 2]} />
      <shaderMaterial
        vertexShader={vertexShader}
        fragmentShader={fragmentShader}
        uniforms={{ uProgress: { value: 0 }, uColor: { value: [color.r, color.g, color.b] } }}
        transparent
      />
    </mesh>
  );
}

export function TransitionCanvas({ progress = 0 }: { progress?: number }) {
  return (
    <Canvas orthographic camera={{ near: -1, far: 1 }} style={{ position: 'fixed', inset: 0, zIndex: 99998, pointerEvents: 'none' }}>
      <TransitionPlane progress={progress} />
    </Canvas>
  );
}`;
    }
    // ── GLSL library ──────────────────────────────────────────────────────────
    getShaderGLSL(type, colorVal) {
        switch (type) {
            case "noise_ripple":
                return `
  uniform float uTime;
  varying vec2 vUv;
  float rand(vec2 n) { return fract(sin(dot(n, vec2(12.9898, 4.1414))) * 43758.5453); }
  float noise(vec2 p) { vec2 i = floor(p); vec2 f = fract(p); float a = rand(i); float b = rand(i+vec2(1,0)); float c = rand(i+vec2(0,1)); float d = rand(i+vec2(1,1)); return mix(mix(a,b,f.x),mix(c,d,f.x),f.y); }
  void main() {
    vec2 uv = vUv + vec2(noise(vUv * 3.0 + uTime * 0.3) - 0.5) * 0.06;
    vec3 col = ${colorVal};
    gl_FragColor = vec4(col, 0.8);
  }`;
            case "wave_warp":
                return `
  uniform float uTime;
  uniform float uVelocity;
  varying vec2 vUv;
  void main() {
    float wave = sin(vUv.x * 8.0 + uTime) * 0.04 * (1.0 + uVelocity * 0.1);
    vec2 uv = vec2(vUv.x, vUv.y + wave);
    vec3 col = ${colorVal};
    gl_FragColor = vec4(col, 0.9);
  }`;
            case "liquid_warp":
                return `
  uniform float uTime;
  varying vec2 vUv;
  float rand(vec2 n) { return fract(sin(dot(n, vec2(12.9898, 4.1414))) * 43758.5453); }
  void main() {
    float t = uTime * 0.2;
    vec2 uv = vUv + vec2(sin(vUv.y * 4.0 + t) * 0.03, cos(vUv.x * 4.0 + t) * 0.03);
    vec3 col = ${colorVal};
    gl_FragColor = vec4(col, 0.85);
  }`;
            case "film_grain_gpu":
                return `
  uniform float uTime;
  varying vec2 vUv;
  float rand(vec2 n) { return fract(sin(dot(n, vec2(12.9898, 4.1414))) * 43758.5453); }
  void main() {
    float grain = rand(vUv + fract(uTime)) * 0.08 - 0.04;
    vec3 col = ${colorVal} + grain;
    gl_FragColor = vec4(col, 1.0);
  }`;
            case "heat_haze":
                return `
  uniform float uTime;
  varying vec2 vUv;
  void main() {
    float shimmer = sin(vUv.y * 20.0 + uTime * 2.0) * 0.003;
    vec2 uv = vec2(vUv.x + shimmer, vUv.y);
    vec3 col = ${colorVal};
    gl_FragColor = vec4(col, 0.9);
  }`;
            case "vhs_dropout":
                return `
  uniform float uTime;
  varying vec2 vUv;
  float rand(vec2 n) { return fract(sin(dot(n, vec2(12.9898, 4.1414))) * 43758.5453); }
  void main() {
    float line = floor(vUv.y * 200.0) / 200.0;
    float noise = rand(vec2(line, floor(uTime * 10.0)));
    float shift = noise * 0.04 * step(0.97, noise);
    vec2 uv = vec2(vUv.x + shift, vUv.y);
    vec3 col = ${colorVal};
    gl_FragColor = vec4(col, 1.0);
  }`;
            case "prismatic":
                return `
  uniform float uTime;
  varying vec2 vUv;
  void main() {
    float r = sin(vUv.x * 5.0 + uTime) * 0.5 + 0.5;
    float g = sin(vUv.y * 5.0 + uTime * 1.2) * 0.5 + 0.5;
    float b = sin((vUv.x + vUv.y) * 4.0 + uTime * 0.8) * 0.5 + 0.5;
    gl_FragColor = vec4(r, g, b, 0.9);
  }`;
            case "data_flow_lines":
                return `
  uniform float uTime;
  varying vec2 vUv;
  void main() {
    float speed = uTime * 0.4;
    float lines = step(0.92, fract((vUv.x * 20.0)));
    float flow = fract(vUv.y + speed) * lines;
    vec3 col = ${colorVal} * flow;
    gl_FragColor = vec4(col, flow * 0.8);
  }`;
            default:
                return `
  varying vec2 vUv;
  void main() { gl_FragColor = vec4(${colorVal}, 1.0); }`;
        }
    }
    // ── post-processing summary ───────────────────────────────────────────────
    /**
     * Generate a comment block listing the post-processing passes that
     * would be applied to this genome's WebGL scene. Actual implementation
     * uses @react-three/postprocessing — passes listed for reference.
     */
    generatePostProcessingComment(genome) {
        const ch12 = genome.chromosomes.ch12_signature;
        const ch8 = genome.chromosomes.ch8_motion;
        const ch14 = genome.chromosomes.ch14_physics;
        const ch13 = genome.chromosomes.ch13_atmosphere;
        const ch11 = genome.chromosomes.ch11_texture;
        const ch10 = genome.chromosomes.ch10_hierarchy;
        const passes = selectPostProcessingPasses({
            philosophy: ch12?.designPhilosophy ?? "editorial",
            material: ch14?.material ?? "standard",
            physics: ch8?.physics ?? "none",
            fx: ch13?.fx ?? "",
            noiseLevel: ch11?.noiseLevel ?? 0,
            shadowScale: ch10?.shadowScale ?? 0,
            entropy: ch12?.entropy ?? 0.5,
        });
        if (passes.length === 0)
            return "// No post-processing passes for this genome";
        return `// Post-processing passes: ${passes.join(", ")}
// Install: npm install @react-three/postprocessing
// Add <EffectComposer> wrapping your Canvas with the following effects:
${passes.map(p => `//   <${this.getEffectName(p)} />`).join("\n")}`;
    }
    getEffectName(pass) {
        const names = {
            bloom_subtle: "Bloom luminanceThreshold={0.5} intensity={0.8}",
            bloom_aggressive: "Bloom luminanceThreshold={0.2} intensity={2.0}",
            film_grain: "Noise opacity={0.15}",
            vignette: "Vignette darkness={0.6}",
            rgb_shift: "ChromaticAberration offset={[0.003, 0.003]}",
            scanlines_gpu: "Scanline density={1.5}",
            depth_of_field: "DepthOfField focusDistance={0} focalLength={0.02} bokehScale={2}",
            chromatic_aberration: "ChromaticAberration offset={[0.002, 0.002]}",
        };
        return names[pass] ?? pass;
    }
}
